import { Link, useLocation } from 'react-router-dom';
import { useState, useEffect } from 'react';

export default function Header() {
  const location = useLocation();
  const [isScrolled, setIsScrolled] = useState(false);
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);

  useEffect(() => {
    const handleScroll = () => {
      setIsScrolled(window.scrollY > 20);
    };
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  useEffect(() => {
    setIsMobileMenuOpen(false);
  }, [location]);

  return (
    <header className="bg-violet-600 text-white py-3 sm:py-4 sticky top-0 z-50 shadow-lg">
      <div className="max-w-7xl mx-auto px-3 sm:px-4 lg:px-8">
        <div className="flex items-center justify-between">
          <Link to="/" className="flex items-center space-x-2 sm:space-x-3">
            <div className="w-10 h-10 sm:w-12 sm:h-12 bg-white/20 rounded-lg sm:rounded-xl flex items-center justify-center flex-shrink-0">
              <i className="fas fa-bolt text-xl sm:text-2xl"></i>
            </div>
            <div>
              <div className="hidden lg:block">
                <h1 className="text-base sm:text-lg font-semibold">Devis décennale Electricien</h1>
              </div>
              <div className="lg:hidden">
                <h1 className="text-sm font-semibold">Décennale</h1>
                <p className="text-xs text-violet-200">Electricien</p>
              </div>
            </div>
          </Link>

          <div className="flex items-center gap-2 sm:gap-3">
            <a 
              href="tel:0182834800" 
              className="hidden sm:flex items-center space-x-2 bg-white/20 px-3 py-2.5 rounded-xl hover:bg-white/30 transition-colors"
            >
              <i className="fas fa-phone text-lg"></i>
              <span className="text-lg font-bold">01 82 83 48 00</span>
            </a>

            <a 
              href="tel:0182834800"
              className="sm:hidden flex items-center justify-center w-10 h-10 bg-white/20 rounded-lg hover:bg-white/30 transition-colors"
            >
              <i className="fas fa-phone text-lg"></i>
            </a>

            <button
              className="lg:hidden p-2 text-white hover:bg-white/20 rounded-lg transition-colors"
              onClick={() => setIsMobileMenuOpen(!isMobileMenuOpen)}
              aria-label="Menu"
            >
              <i className={`fas ${isMobileMenuOpen ? 'fa-times' : 'fa-bars'} text-xl`}></i>
            </button>
          </div>
        </div>

        {isMobileMenuOpen && (
          <div className="lg:hidden mt-4 pb-4 border-t border-white/20 pt-4">
            <div className="flex flex-col space-y-3">
              <a 
                href="tel:0182834800" 
                className="flex items-center justify-center space-x-2 bg-white/20 px-4 py-3 rounded-xl hover:bg-white/30 transition-colors"
              >
                <i className="fas fa-phone text-lg"></i>
                <span className="text-lg font-bold">01 82 83 48 00</span>
              </a>
              {location.pathname === '/' && (
                <a 
                  href="#quote" 
                  className="block text-center bg-white text-violet-600 font-semibold px-4 py-3 rounded-xl hover:bg-gray-100 transition-colors"
                >
                  Demander un devis
                </a>
              )}
            </div>
          </div>
        )}
      </div>
    </header>
  );
}
